import{_ as t,o as r,c as p,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"0.写在前面","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/0.写在前面.md","filePath":"7.UA/0.写在前面.md"}'),o={name:"7.UA/0.写在前面.md"};function d(_,e,l,i,c,h){return r(),p("div",null,[...e[0]||(e[0]=[a("h1",{id:"_0-写在前面",tabindex:"-1"},[n("0.写在前面 "),a("a",{class:"header-anchor",href:"#_0-写在前面","aria-label":'Permalink to "0.写在前面"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：新秩序001")])])],-1),s('<h1 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h1><p>无限规则是一个鼓励大家玩自己所爱的资源的一种规则，所以虽然说本书对于所谓的官方规则有一些小偏执，但是我们并不是要求所有人必须做到最好，资源每一个都独具匠心，这是不可能的。</p><p>所以在此我们提出UA概念，这是我从隔壁DND偷来的一个概念，在龙与地下城游戏中，有很多非官方资源或者说虽然是官方资源，但是官方不愿意将其转正的一些资源，通常来说都会丢进UA里。</p><p>所谓UA就是旨在鼓励大家写出自己想玩的画风，只要你符合规则，就算直接点又如何呢？</p><p>我们是来在TRPG中得到快乐，而不是在强迫自己必须尽善尽美，希望从这里开始，我们往后的UA将日益壮大。</p><p>那么依旧惯例感谢一下为UA提供资源的诸位：</p><p>Kira、面粉、鄂木斯克铲种、阿蒙</p><p>PS：由于我更新时间尚晚，没有确认三位是否需要化名，如果需要，请联系我，将在下一版号中修正，此中带来的不便敬请见谅。</p><p>以上</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const b=t(o,[["render",d]]);export{A as __pageData,b as default};
